const { items, sprint, team } = $input.first().json;
const byCategory = {};
for (const item of items) {
  byCategory[item.category] = byCategory[item.category] || [];
  byCategory[item.category].push(item.text);
}
const format = (cat) => (byCategory[cat] || []).map((t, i) => `  [${i+1}] ${t}`).join('\n');
const system = `You are a sprint coach helping a product engineering team extract actionable patterns from their retrospective. Identify recurring themes, not just list items. Be specific. Return ONLY valid JSON.`;
const user = `Analyse these ${items.length} retrospective items from ${sprint} (${team}) and produce a structured retrospective report.

WENT WELL:
${format('went_well')}

TO IMPROVE:
${format('to_improve')}

ACTIONS:
${format('action')}

Return JSON:
{
  "went_well_themes": [{ "theme": "string", "items_count": 2, "key_insight": "string" }],
  "improvement_themes": [{ "theme": "string", "items_count": 2, "root_cause": "string", "recurring": true }],
  "prioritised_actions": [{ "action": "string", "owner": "string or 'team'", "by_when": "next sprint | this week | ongoing", "addresses_theme": "string" }],
  "team_health_signal": "improving|stable|declining",
  "team_health_rationale": "string",
  "patterns_to_watch": ["string"]
}`;
return [{ json: { items, sprint, team, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Analysis Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
const req = ['went_well_themes', 'improvement_themes', 'prioritised_actions'];
const missing = req.filter(k => !parsed[k]);
if (missing.length) return [{ json: { _error: true, reason: `Missing: ${missing.join(',')}` } }];
return [{ json: { _error: false, analysis: parsed, meta: { sprint: upstream.sprint, team: upstream.team, total: upstream.items.length, generated_at: new Date().toISOString() } } }];
